llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
    auto& irb = *mCurIrb;
    auto decl = obj->decl->dcst<VarDecl>();
    if (!decl) ABORT();

    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any)) {
        return irb.CreateLoad(self(decl->type), alloca, decl->name);
    }
    else if (auto gvar = llvm::dyn_cast<llvm::GlobalVariable>(decl->any)) {
        return irb.CreateLoad(self(decl->type), gvar, decl->name);
    }
    ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
    auto& irb = *mCurIrb;
    auto lft = self(obj->lft);
    auto rht = self(obj->rht);

    switch (obj->op) {
        case BinaryExpr::Op::kAdd:
            return irb.CreateAdd(lft, rht, "addtmp");
        case BinaryExpr::Op::kSub:
            return irb.CreateSub(lft, rht, "subtmp");
        case BinaryExpr::Op::kMul:
            return irb.CreateMul(lft, rht, "multmp");
        case BinaryExpr::Op::kDiv:
            return irb.CreateSDiv(lft, rht, "divtmp");
        case BinaryExpr::Op::kAssign:
            if (auto declRef = obj->lft->dcst<DeclRefExpr>()) {
                auto decl = declRef->decl->dcst<VarDecl>();
                if (!decl) ABORT();

                if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any)) {
                    return irb.CreateStore(rht, alloca);
                }
                else if (auto gvar = llvm::dyn_cast<llvm::GlobalVariable>(decl->any)) {
                    return irb.CreateStore(rht, gvar);
                }
            }
            ABORT();
        default:
            ABORT();
    }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
    auto& irb = *mCurIrb;
    auto sub = self(obj->sub);

    switch (obj->op) {
        case UnaryExpr::Op::kNeg:
            return irb.CreateNeg(sub, "negtmp");
        default:
            ABORT();
    }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
    auto& irb = *mCurIrb;

    // Look up function
    auto func = llvm::dyn_cast<llvm::Function>(mMod.getFunction(obj->head->dcst<DeclRefExpr>()->decl->name));
    if (!func) ABORT();

    // Prepare arguments
    std::vector<llvm::Value*> args;
    for (auto arg : obj->args) {
        args.push_back(self(arg));
    }

    return irb.CreateCall(func, args, "calltmp");
}

